                formatted_val = _to_text(val, "%Y-%m-%d", "%Y-%m-%d %H:%M:%S", "%H:%M:%S")
                row_out.append(formatted_val)
            yield row_out

    _stream_write_csv(out_path, _iter_filtered_rows(), encoding, bom)
    return out_path

